var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"큭?! 일격 한 번에 무기가...!","JPN":"くっ！？　一撃で武器が……！","ENG":"Kgh?! My weapon... shattered in a single strike...?!","TWN":"咳？！只發動一擊武器就……！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L4_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"거기까지다.","JPN":"ここまでだ。","ENG":"That's enough.","TWN":"到此為止。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"레아 님!","JPN":"レア様！","ENG":"Ms. Leah!","TWN":"蕾亞！"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"이건 진짜...","JPN":"これはマジで……","ENG":"She's seriously...","TWN":"這也太……"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...더럽게 강하잖아.","JPN":"……強すぎる。","ENG":"...insanely strong.","TWN":"……厲害了吧。"},"stage":{"bg":"BLACK","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L11_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"안... 돼.","JPN":"ダ……メ。","ENG":"No...!","TWN":"不……行。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"미안하구나, 아우드라.","JPN":"すまない、アウドラ。","ENG":"I'm sorry, Audra.","TWN":"對不起，奧德拉。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"MORS_SHADOW_ANAP_QM","text":{"KOREA":"좀 더 일찍 결단을 내렸어야 했는데, 내가 너무 늦게 와버렸어.","JPN":"もっと早く決断すべきだったが、遅くなりすぎてしまった。","ENG":"I should have made the decision sooner, but I came too late.","TWN":"我應該更早下定決心的，是我來得太晚了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_ANAP_QM","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"해는 아직 저물지 않은 걸요.","JPN":"まだ日は暮れていません。","ENG":"The sun has not set yet.","TWN":"太陽還沒有落下呢。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"DASH_ANAP_CA_NULL","text":{"KOREA":"늦지 않았어요. 이번에도.","JPN":"まだ間に合います。今回も。","ENG":"It's not too late. Not this time either.","TWN":"這次也不算晚。"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"DASH_ANAP_CA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"해?","JPN":"日？","ENG":"The sun?","TWN":"太陽？"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GUN","text":{"KOREA":"그러고 보니, 지난 번에도 이 무렵에...","JPN":"そういえば、この前もこの時間に……","ENG":"Come to think of it, last time it was around this time as well...","TWN":"這麼說來，上次也是在這個時候……"},"stage":{"bg":"FOREST_NORMAL","bgm":"BATTLE_BOSS_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GUN","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...헉!","JPN":"……はっ！","ENG":"...Kuh!","TWN":"……啊！"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L20_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_HATE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"좋은 아침이구나, 레아야.","JPN":"おはよう、レア。","ENG":"Good morning, Leah.","TWN":"早安，蕾亞。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"엄마? 여긴... 집이네요?","JPN":"お母さん？　ここは……家だよね？","ENG":"Mom? This is... home?","TWN":"媽媽？這裡是……家？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"전 분명... 죽었다고 생각했는데. 눈을 떠보니 여기에 있어요.","JPN":"絶対……死んだと思ったのに。目覚めたらここにいたの。","ENG":"I was sure... I had died. But when I opened my eyes, I was here.","TWN":"我明明以為自己已經死了。可是一睜開雙眼，就回到這裡了。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"낙원에서는 모든 것의 시작과 끝이 맞닿은 채 순환한단다.","JPN":"楽園ではどんなものでも始まりと終わりが繋がって循環しているわ。","ENG":"In the Promised Land, the beginning and end of everything meet and repeat in a cycle.","TWN":"在樂園裡，一切的開始與終結都彼此相連並循環。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"생과 죽음 역시도 마찬가지지.","JPN":"生と死も同じ。","ENG":"Life and death are no exception.","TWN":"生與死也是如此。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...하루가 지나면, 죽음이고 뭐고 전부 없었던 일이 된다는 말씀이세요?","JPN":"……一日が終われば、死も何もかもが全部なかったことになるってこと？","ENG":"...So after a day passes, death and everything else are simply undone?","TWN":"……也就是說，只要過了一天，死亡之類的事情會像從未發生過一樣？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"하나 예외가 있다면, 우리 모두 오늘과 그 다음 오늘이 서로 다른 오늘이란 걸 기억하고 있다는 점이지.","JPN":"一つだけ例外があるとすれば、みんなが今日とその次の今日を別の日として覚えているところね。","ENG":"The only exception is that we all remember that today and the next today are different days.","TWN":"唯一的例外，是我們所有人都記得，今天與下一個今天其實是不同的今天。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"모든 사람들의 마음엔 잊고 싶지 않아하는 소망이 있으니까.","JPN":"誰の心にも忘れたくない願いがあるから。","ENG":"Because everyone has a wish they don't want to forget.","TWN":"因為每個人的心裡，都有不願忘記的願望。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"소망이라...","JPN":"願いか……","ENG":"A wish...","TWN":"願望嗎……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"만약 제가 지금 낙원을 떠나게 된다면, 그 다음엔 어떻게 되죠?","JPN":"もし私が今楽園を出たら、その後はどうなるのかな？","ENG":"If I were to leave the Promised Land right now, what would happen then?","TWN":"如果我現在離開樂園，之後會怎麼樣？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"네가 어디에 있든, 오늘이 지나면 다시 이곳에서 눈을 뜨겠지.","JPN":"あなたがどこにいても、今日が過ぎたらまたここで目覚めることになるわ。","ENG":"No matter where you are, once today ends, you will wake up here again.","TWN":"無論你在哪裡，只要今天結束，明天你依然會在這裡醒來。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"너 역시 낙원의 주민이니까.","JPN":"あなたも楽園の住民だから。","ENG":"Because you are also a resident of the Promised Land.","TWN":"因為你也是樂園的居民。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"낙원에서 벗어나는 게... 제 소망이라고 해도 말인가요?","JPN":"楽園から出るのが……私の願いだとしても？","ENG":"Even if my wish is... to escape the Promised Land?","TWN":"就算……離開樂園是我的願望也一樣嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"그 질문은 네 스스로에게 해봐야지.","JPN":"その質問は、あなた自身にしないと。","ENG":"That is something you must ask yourself.","TWN":"那個問題，應該由你自己回答。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"OLD_GRONIA_NULL_NULL","text":{"KOREA":"레아야. 넌 정말 이곳을 떠나고 싶은 게 맞니?","JPN":"レア。あなたは本当にここから出たいの？","ENG":"Leah, do you truly wish to leave this place?","TWN":"蕾亞，你真的想離開這裡嗎？"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"OLD_GRONIA_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"열려라...","JPN":"開け……","ENG":"Lid...","TWN":"打開吧……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"뚜껑!","JPN":"フタ！","ENG":"Open!","TWN":"蓋子！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"으으음... 이게 아닌가?","JPN":"うーん……これではなかったでしょうか？","ENG":"Hmm... is that not it?","TWN":"嗯……不是這樣嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L42_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"열라... 뚜껑? 두껍?","JPN":"開けろ……フタ？　キャップ？","ENG":"Lit... open? Lip?","TWN":"打開……蓋子？厚蓋子？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"열! 려! 주시어요오오!!!","JPN":"開・い・て・くださいませせせせ！！！","ENG":"Please! Opeeeen!!!","TWN":"打！開！吧！！！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L45_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"주문은 안 틀렸어요.","JPN":"呪文は間違ってないよ。","ENG":"The spell is correct.","TWN":"咒語沒有念錯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L46_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"...앗, 클라라 님?","JPN":"……あっ、クララ様？","ENG":"...Ah, Ms. Clara?","TWN":"……啊，克拉拉？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L47_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"근데 친구는 내 목소리만 인식해.","JPN":"でも友だちはクララの声だけ認識するの。","ENG":"But my friend only recognizes my voice.","TWN":"不過朋友只會識別我的聲音。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L48_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"거기서... 다 듣고 계셨사옵니까?","JPN":"そこで……全部聞いていらしたのですか？","ENG":"You were... listening to all that?","TWN":"剛才……你都聽到了嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L49_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응. 재밌어 보여서.","JPN":"うん。面白そうだったから。","ENG":"Yes. It looked fun.","TWN":"嗯，因為看起來很有趣。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"부, 부끄럽고 송구합니다.","JPN":"は、恥ずかしいし、申し訳ございません。","ENG":"I-I'm embarrassed and sorry.","TWN":"我好失、失禮又丟臉。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L1_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"무기를 조금이라도 빨리 챙기고 싶은 마음에 소녀 혼자 여기까지 와버려서는...","JPN":"武器を少しでも早く取りたいと思うあまり、わたくし1人でここまで来てしまい……","ENG":"I came all the way here alone because I wanted to prepare a weapon as quickly as possible...","TWN":"我只是因為想更快拿到武器，一個人跑到這裡……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L2_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"무기 또 필요해요? 앞으로도 계속?","JPN":"武器、また必要なの？　これからもずっと？","ENG":"You need another weapon? And maybe more after that?","TWN":"還需要武器嗎？以後也會一直需要嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L3_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그게... 소녀도 이번이 마지막이면 좋겠사옵니다만...","JPN":"それが……わたくしも今回が最後であってほしいのですが……","ENG":"Well... I do hope this will be the last time...","TWN":"這個……我也希望這是最後一次……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"빌려줄게. 몇 번이든.","JPN":"貸してあげるよ。何度でも。","ENG":"I'll lend you one. As many times as you need.","TWN":"我會借你，不管幾次都可以。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"정말이옵니까?","JPN":"本当でございますか？","ENG":"Really?","TWN":"真的嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"대신, 나도 따라갈래.","JPN":"その代わり、私もついて行く。","ENG":"But in return, I want to come with you.","TWN":"不過，作為交換，我也要一起去。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"아...","JPN":"あ……","ENG":"Ah...","TWN":"啊……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그건 별로 좋은 생각이 아닌 것 같사옵니다.","JPN":"それはあまり良い考えではないと思います。","ENG":"I don't think that's a very good idea.","TWN":"那恐怕不是什麼好主意。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"왜?","JPN":"どうして？","ENG":"Why?","TWN":"為什麼？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"네가 보기에 좋은 광경은 아닐 거야.","JPN":"見ていて楽しい光景じゃないはずだもの。","ENG":"It won't be a pleasant sight for you.","TWN":"畫面不會太好看。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"무기를 쓴다는 건, 누군가가 다치게 된다는 뜻이니까.","JPN":"武器を使うってことは、誰かが怪我するってことだから。","ENG":"Using weapons means someone will get hurt.","TWN":"使用武器，就代表會有人受傷。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"안 다치면, 레아 씨가 원하는 거 못 가져?","JPN":"怪我しないと、レアさんが欲しいものって手に入らない？","ENG":"If no one gets hurt, you can't get what you want, Ms. Leah?","TWN":"如果沒有人受傷，蕾亞就拿不到想要的東西嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"말로 해결할 수 있다면 그게 가장 좋겠지만... 가끔은 그런 게 꼭 필요하거든.","JPN":"言葉で解決できるならそれがベストだけど……たまにそんなものが絶対必要になることがあるんだよ。","ENG":"If things can be settled with words, that would be best... but sometimes that's not possible.","TWN":"如果能用講的解決當然最好……但有時候還是不得不那麼做。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"특히, 자기가 죽는 게 소원인 사람을 막으려면 말이지.","JPN":"特に、死ぬことを願う人を食い止めるためにはね。","ENG":"Especially when you're trying to stop someone whose wish is to die.","TWN":"特別是要阻止那些把死亡當作願望的人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_07","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"정말 괜찮겠어?","JPN":"本当に大丈夫？","ENG":"Are you really okay with that?","TWN":"真的沒關係嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"응.","JPN":"うん。","ENG":"Yes.","TWN":"嗯。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"소망을 이루는 건 좋은 거지만, 죽는 건 좋지 않아.","JPN":"願いをかなえるのはいいことだけど、死ぬのはよくない。","ENG":"It's good for wishes to come true, but dying isn't good.","TWN":"實現願望是好事，但死亡不是。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPIRIT_RAS_NPC_CLARA","text":{"KOREA":"클라라도 그 사람이 죽지 않게 도울래.","JPN":"クララも、あの人が死なないように助ける。","ENG":"I want to help so that person doesn't die either.","TWN":"克拉拉也想幫忙，讓那個人不要死。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPIRIT_RAS_NPC_CLARA","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"돌아가면, 그분은 이번에도 그 자리에 있을 테지요.","JPN":"戻ったら、あの方は今回もあの場にいますよね。","ENG":"When we return, she'll probably be in the same place again this time.","TWN":"等我們回去時，那位大概還會在那裡吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그래. 언제 죽었냐는 듯 아마 가지치기 같은 걸 하고 있겠지.","JPN":"うん。死んだことなんてなかったように、たぶん剪定とかしてると思う。","ENG":"Yeah. As if nothing happened, she'll probably be trimming branches again.","TWN":"是啊。應該會像從來沒死過一樣，還在修剪樹枝吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"낙원에 죽음이 없다곤 하나, 그분의 죽음은 무언가 달랐사옵니다.","JPN":"楽園に死はないといえ、あの方の死は何かが違っておりました。","ENG":"They say there is no death in the Promised Land, yet her death felt... different.","TWN":"雖然樂園裡沒有死亡，但那位的死亡似乎有些不同。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"달랐다고?","JPN":"違う？","ENG":"Different?","TWN":"不同？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"우리처럼 죽었다가 되살아나는 것 말고도, 다른 점이 있다는 거야?","JPN":"私たちみたいに死んで蘇ること以外にも、違うところがあるってこと？","ENG":"You mean there's something different from how we die and come back?","TWN":"除了像我們一樣死了又復活之外，還有其他差別嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"저를 닮은 여인이 아우드라 님을 죽이기 위해 나타날 땐... 항상 해가 저물고 있었사옵니다.","JPN":"わたくしに似た女性がアウドラ様を殺すために現れる時……いつも日が暮れておりました。","ENG":"Whenever the woman who resembles me appears to kill Ms. Audra... the sun is always setting.","TWN":"每當那個與我長得相似的女人出現，試圖殺死奧德拉時……太陽總正要落下。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"그분의 죽음을 목도한 뒤엔, 다시 아침이 되어있었지요.","JPN":"あの方の死を目撃した後は、朝に戻っていたのです。","ENG":"And after witnessing her death, it's morning again.","TWN":"等我們親眼目睹那位的死亡後，又會重新變成早晨。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"그 말은... 아우드라의 죽음이, 하루가 반복되는 것과 연관이 있다는 건가?","JPN":"それって……アウドラの死が、一日が繰り返されることと関係があるってこと？","ENG":"So... Audra's death might be connected to the day repeating?","TWN":"意思是……奧德拉的死亡，與一天的循環有關？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"단언할 수는 없으나, 직접 확인할 가치는 있을 것으로 아뢰옵니다.","JPN":"断言はできませんが、直接確認する価値はあると思うのでございます。","ENG":"I can't say for certain, but it seems worth confirming ourselves.","TWN":"我不敢斷言，但確實值得親自確認。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...그래. 돌이켜보면 근거는 충분했어.","JPN":"……そうか。振り返ってみると、根拠は十分あったね。","ENG":"...Yeah. Thinking back, there's enough evidence.","TWN":"……也是。現在回想起來，其實有很多證據。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"낙원을 만든 게 아우드라 그녀라면, 낙원이 매일을 되풀이하도록 설계한 것도 자기 자신일 테니까.","JPN":"楽園を作ったのがアウドラなら、楽園に同じ日が繰り返されるように設計したのも自分自身のはず。","ENG":"If Audra's the one who created the Promised Land, then she must also be the one who designed it to repeat each day.","TWN":"如果創造樂園的人是奧德拉，那麼讓樂園每天重複循環的人，恐怕也是她自己。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"하루의 끝을 자신의 죽음과 이어 놓은 걸지도 모르지. 그게 낙원의 주민들이 지금껏 밤을 볼 수 없었던 이유고.","JPN":"一日の終わりを自分の死に繋げておいたのかも。それが楽園の住民たちが今まで夜を見ることのできなかった理由で。","ENG":"She may have linked the end of the day to her own death. That would explain why the residents of the Promised Land have never seen night.","TWN":"也許她把一天的結束與自己的死亡連在一起，這大概就是為什麼樂園的居民至今從未見過夜晚。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"아우드라는, 낙원이 가진 또 하나의 이름이란다.","JPN":"アウドラは、この楽園のもう一つの名前だよ。","ENG":"Audra is another name for the Promised Land itself.","TWN":"奧德拉，是樂園的另一個名字。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":".......","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L41_1","type":"dialog","speaker":"MORS_SHADOW_NPC_GIRL","text":{"KOREA":"혹 그분에겐, 밤이 와서는 안될 이유라도 있는 것일까요?","JPN":"もしかしてあの方には、夜が来てはいけない理由でもあるのでしょうか？","ENG":"Could it be that there is a reason night must never come for her?","TWN":"難道她有什麼理由，不能讓夜晚到來嗎？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"글쎄. 어두운 걸 지독히도 무서워하기 때문이려나?","JPN":"どうかな。暗いのをすごく怖がるからとか？","ENG":"Who knows. Maybe she's just terribly afraid of the dark.","TWN":"不知道，也許只是因為她非常害怕黑暗？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"뭐가 됐든. 그 여자가 죽는 걸 막아서 이 순환도 멈출 수만 있다면, 난 몇 번이든 계속 해보겠어.","JPN":"ともかく。あの女が死ぬのを食い止めることでこの循環も止めることができるなら、私は何度でもやってみるつもり。","ENG":"Whatever the reason, if we can stop her from dying and end this cycle... I'll try as many times as it takes.","TWN":"無論如何，只要能阻止那女人死去、讓這個循環停止，要嘗試多少次我都願意。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"MORS_SHADOW_NPC_GIRL","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"외지인이 이곳에 당도하는 이유는 단 하나.","JPN":"よそ者がここにたどり着く理由はたった一つ。","ENG":"There is only one reason outsiders arrive here.","TWN":"外地人來到這裡，只有一個原因。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"DEMON_VELES_NPC_NULL","text":{"KOREA":"낙원이 그러길 바랐기 때문입니다.","JPN":"楽園がそれを望んだからです。","ENG":"Because the Promised Land wished it so.","TWN":"樂園希望如此。"},"stage":{"bg":"WOODHOUSE","bgm":"CUTSCENE_TALK_06","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"DEMON_VELES_NPC_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"AGENT_GRONIA_WHITE_NAME","text":{"KOREA":"...성공하면, 낙원에서 벗어나 현실로 돌아가는 것도 가능해지겠지.","JPN":"……成功したら、楽園から出て現実に戻ることだってできるだろうし。","ENG":"...If we succeed, then maybe we'll be able to leave the Promised Land and return to reality.","TWN":"……如果成功了，也許就能離開樂園、回到現實。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_06","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"AGENT_GRONIA_WHITE_NAME","face":"UNIT_SERIOUS"},"R":null}}}]`);export{e as default};